const businesses = $input.all().map(i => i.json);
const flat = Array.isArray(businesses[0]) ? businesses[0] : businesses;

const today = new Date().toISOString().split('T')[0];

// Build dynamic repos list from businesses + always include sluice-orchestration
const repos = ['sluice-orchestration'];
for (const b of flat) {
  if (b.repo_name && !repos.includes(b.repo_name)) {
    repos.push(b.repo_name);
  }
}

// Build dynamic RLS tables list
// Core tables that always need checking + business-specific ones
const tables = ['businesses', 'users', 'repair_orders', 'customers', 'invoices', 'line_items', 'inspections', 'inspection_items'];

return [{
  json: {
    date: today,
    supabaseUrl: 'https://wjukfdziomnejtlmegvv.supabase.co',
    supabaseAnonKey: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6IndqdWtmZHppb21uZWp0bG1lZ3Z2Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzM1Mjk1ODIsImV4cCI6MjA4OTEwNTU4Mn0.12Vszqd1Lhp0M6FIB_pSF1l7T_SscB0X4AxwFTRrTVU',
    githubOwner: 'ShalinPatel670',
    repos: repos,
    n8nUrl: 'https://n8n-production-bb4b.up.railway.app',
    tables: tables,
    businesses: flat
  }
}];

// Dynamic .env check - check all repos from businesses table
const config = $('Setup Config (Dynamic)').first().json;
const repos = config.repos || [];
const results = [];

// We output each repo as an item for the next node to check
return repos.map(repo => ({ json: { repo, owner: config.githubOwner } }));

// Dynamic CLAUDE.md check for all repos
const config = $('Setup Config (Dynamic)').first().json;
return config.repos.map(repo => ({ json: { repo, owner: config.githubOwner } }));

const findings = [];
const config = $('Setup Config (Dynamic)').first().json;
const date = config.date;

function addFinding(severity, category, title, detail, remediation) {
  findings.push({ severity, category, title, detail, remediation });
}

// --- 1. RLS Checks ---
const rlsNodes = [
  { name: 'Check RLS - businesses', table: 'businesses' },
  { name: 'Check RLS - users', table: 'users' },
  { name: 'Check RLS - repair_orders', table: 'repair_orders' },
  { name: 'Check RLS - customers', table: 'customers' },
  { name: 'Check RLS - invoices', table: 'invoices' },
  { name: 'Check RLS - inspections', table: 'inspections' }
];

for (const rls of rlsNodes) {
  try {
    const result = $(rls.name).first().json;
    const hasError = result.error || result.message || result.code;
    if (Array.isArray(result) && result.length > 0) {
      addFinding('CRITICAL', 'RLS', 'RLS bypass on ' + rls.table,
        'Anon key returned data from ' + rls.table + ' table.',
        'Enable RLS on ' + rls.table + ': ALTER TABLE ' + rls.table + ' ENABLE ROW LEVEL SECURITY;');
    }
    const allItems = $(rls.name).all();
    if (allItems.length > 1) {
      addFinding('CRITICAL', 'RLS', 'RLS bypass on ' + rls.table,
        'Anon key returned ' + allItems.length + ' rows from ' + rls.table + '.',
        'Enable RLS: ALTER TABLE ' + rls.table + ' ENABLE ROW LEVEL SECURITY;');
    } else if (allItems.length === 1 && !hasError) {
      const keys = Object.keys(result);
      const nonErrorKeys = keys.filter(k => !['error', 'message', 'code', 'hint', 'details', 'statusCode'].includes(k));
      if (nonErrorKeys.length > 0 && result.id !== undefined) {
        addFinding('CRITICAL', 'RLS', 'RLS bypass on ' + rls.table,
          'Anon key returned record data from ' + rls.table + '.',
          'Enable RLS on ' + rls.table + '.');
      }
    }
  } catch (e) { /* blocked - good */ }
}

// --- 2. Dynamic .env file checks ---
try {
  const envResults = $('Check .env (Dynamic Repos)').all();
  const envRepos = $('Build Dynamic Env Checks').all();
  for (let i = 0; i < envResults.length; i++) {
    const result = envResults[i].json;
    const repoInfo = envRepos[i] ? envRepos[i].json : {};
    const repo = repoInfo.repo || 'unknown';
    if (result.content || result.sha || result.name === '.env') {
      addFinding('CRITICAL', 'SECRETS', 'Exposed .env in ' + repo,
        '.env file found committed in ' + repo + ' repository.',
        'Remove .env from repo: git rm --cached .env && add .env to .gitignore && rotate all exposed credentials.');
    }
  }
} catch (e) { /* no results */ }

// --- 3. Secrets in code search ---
try {
  const codeSearch = $('Check Secrets in Code').first().json;
  if (codeSearch.total_count && codeSearch.total_count > 0) {
    const items = codeSearch.items || [];
    const fileList = items.slice(0, 10).map(i => i.repository.full_name + '/' + i.path).join(', ');
    addFinding('CRITICAL', 'SECRETS', 'API keys/secrets found in code',
      'GitHub code search found ' + codeSearch.total_count + ' file(s) potentially containing secrets: ' + fileList,
      'Audit each file. Remove secrets, use environment variables instead.');
  }
} catch (e) { /* search failed */ }

// --- 4. Dynamic CLAUDE.md secrets check ---
try {
  const claudeResults = $('Check CLAUDE.md (Dynamic Repos)').all();
  const claudeRepos = $('Build Dynamic CLAUDE.md Checks').all();
  for (let i = 0; i < claudeResults.length; i++) {
    const result = claudeResults[i].json;
    const repoInfo = claudeRepos[i] ? claudeRepos[i].json : {};
    const repo = repoInfo.repo || 'unknown';
    if (result.content) {
      const decoded = Buffer.from(result.content, 'base64').toString('utf8');
      const secretPatterns = [
        { pat: /sk-ant-[a-zA-Z0-9-]+/, label: 'Anthropic API key' },
        { pat: /SUPABASE_SERVICE_ROLE[=:]/, label: 'Supabase service role key' },
        { pat: /ghp_[a-zA-Z0-9]+/, label: 'GitHub personal access token' },
        { pat: /password\s*[=:]\s*['"][^'"]+['"]/i, label: 'Hardcoded password' },
        { pat: /sk_live_[a-zA-Z0-9]+/, label: 'Stripe live key' },
        { pat: /sk_test_[a-zA-Z0-9]+/, label: 'Stripe test key' },
        { pat: /PRIVATE_KEY/, label: 'Private key reference' }
      ];
      for (const { pat, label } of secretPatterns) {
        if (pat.test(decoded)) {
          addFinding('CRITICAL', 'SECRETS', 'Secret in CLAUDE.md (' + repo + ')',
            'CLAUDE.md in ' + repo + ' contains a ' + label + '.',
            'Remove secrets from CLAUDE.md.');
          break;
        }
      }
    }
  }
} catch (e) { /* no results */ }

// --- 5. n8n exposure checks ---
try {
  const settingsResult = $('Check n8n Settings Exposed').first().json;
  if (settingsResult && !settingsResult.error && !settingsResult.statusCode && settingsResult.data) {
    addFinding('HIGH', 'N8N', 'n8n settings endpoint exposed',
      'The /rest/settings endpoint returned data without authentication.',
      'Ensure N8N_BASIC_AUTH_ACTIVE=true.');
  }
} catch (e) { /* blocked - good */ }

try {
  const setupResult = $('Check n8n Setup Page').first().json;
  if (setupResult && !setupResult.error) {
    const body = JSON.stringify(setupResult);
    if ((body.includes('setup') || body.includes('owner') || body.includes('Create')) && body.length > 100) {
      addFinding('HIGH', 'N8N', 'n8n setup page accessible',
        'The /setup endpoint appears to be accessible.',
        'Ensure n8n is properly configured and initial setup is complete.');
    }
  }
} catch (e) { /* blocked - good */ }

// --- Deduplicate ---
const seen = new Set();
const dedupedFindings = findings.filter(f => {
  if (seen.has(f.title)) return false;
  seen.add(f.title);
  return true;
});

const critical = dedupedFindings.filter(f => f.severity === 'CRITICAL');
const high = dedupedFindings.filter(f => f.severity === 'HIGH');
const medium = dedupedFindings.filter(f => f.severity === 'MEDIUM');
const low = dedupedFindings.filter(f => f.severity === 'LOW');

let report = '# Security Audit Report - ' + date + '\n\n';
report += '**Run time:** ' + new Date().toISOString() + '\n';
report += '**Agent:** Security Agent v2.0 (Multi-Business)\n';
report += '**Repos scanned:** ' + config.repos.join(', ') + '\n\n';
report += '## Summary\n\n';
report += '| Severity | Count |\n|----------|-------|\n';
report += '| CRITICAL | ' + critical.length + ' |\n';
report += '| HIGH | ' + high.length + ' |\n';
report += '| MEDIUM | ' + medium.length + ' |\n';
report += '| LOW | ' + low.length + ' |\n';
report += '| **Total** | **' + dedupedFindings.length + '** |\n\n';

if (dedupedFindings.length === 0) {
  report += '**All checks passed. No security issues detected.**\n\n';
} else {
  report += '## Findings\n\n';
  for (const f of dedupedFindings) {
    report += '### [' + f.severity + '] ' + f.title + '\n\n';
    report += '- **Category:** ' + f.category + '\n';
    report += '- **Detail:** ' + f.detail + '\n';
    report += '- **Remediation:** ' + f.remediation + '\n\n';
  }
}

report += '## Checks Performed\n\n';
report += '- [x] Supabase RLS verification (6 tables)\n';
report += '- [x] GitHub .env file exposure (' + config.repos.length + ' repos - dynamic)\n';
report += '- [x] GitHub code secret scan\n';
report += '- [x] CLAUDE.md secret scan (' + config.repos.length + ' repos - dynamic)\n';
report += '- [x] n8n admin API exposure\n';
report += '- [x] n8n setup page exposure\n';

return [{
  json: {
    date,
    report,
    findings: dedupedFindings,
    criticalCount: critical.length,
    highCount: high.length,
    mediumCount: medium.length,
    lowCount: low.length,
    totalFindings: dedupedFindings.length,
    hasCritical: critical.length > 0,
    hasHigh: high.length > 0,
    needsAlert: critical.length > 0 || high.length > 0,
    needsIssues: critical.length > 0 || high.length > 0,
    criticalFindings: critical,
    highFindings: high
  }
}];

