const data = $('Analyze Security Results').first().json;
const config = $('Setup Config (Dynamic)').first().json;
const issues = [];

const actionableFindings = [...data.criticalFindings, ...data.highFindings];

for (const finding of actionableFindings) {
  // Determine which repo to file the issue against
  let repo = 'sluice-orchestration';
  // Check if finding mentions a specific business repo
  for (const r of config.repos) {
    if (finding.detail.includes(r) || finding.title.includes(r)) {
      repo = r;
      break;
    }
  }
  if (finding.category === 'RLS') repo = config.repos.find(r => r !== 'sluice-orchestration') || 'sluice-orchestration';

  const body = '## Security Finding: ' + finding.title + '\n\n'
    + '**Severity:** ' + finding.severity + '\n'
    + '**Category:** ' + finding.category + '\n'
    + '**Detected:** ' + data.date + '\n\n'
    + '### Detail\n' + finding.detail + '\n\n'
    + '### Remediation\n' + finding.remediation + '\n\n'
    + '---\n'
    + '*Auto-generated by Security Agent. @claude please investigate and fix.*';

  issues.push({
    json: {
      repo,
      title: '[' + finding.severity + '] ' + finding.title,
      body,
      labels: ['security', 'automated']
    }
  });
}

if (issues.length === 0) {
  return [{ json: { skip: true, message: 'No issues to create' } }];
}

return issues;
